let propId = '';
try { propId = $('Webhook').first().json.body?.propId || ''; } catch (e) {}
if (!propId) { try { propId = $('Build updated config').first().json?.propId || ''; } catch (e) {} }
if (!propId) throw new Error('No propId found');

function fsVal(field) {
  if (!field) return null;
  if (field.stringValue  !== undefined) return field.stringValue;
  if (field.booleanValue !== undefined) return field.booleanValue;
  if (field.integerValue !== undefined) return Number(field.integerValue);
  if (field.mapValue) {
    const out = {};
    for (const [k,v] of Object.entries(field.mapValue.fields||{})) out[k] = fsVal(v);
    return out;
  }
  return null;
}

const doc = $input.first().json;
const arr = doc.fields?.properties?.arrayValue?.values || [];

const match = arr.map(item => {
  const m = item.mapValue?.fields || {};
  return {
    id:             fsVal(m.id)             || '',
    driveId:        fsVal(m.driveId)        || '',
    itemId:         fsVal(m.itemId)         || '',
    property:       fsVal(m.property)       || '',
    address:        fsVal(m.address)        || '',
    yardi_url:      fsVal(m.yardi_url)      || '',
    sharepoint_url: fsVal(m.sharepoint_url) || ''
  };
}).find(p => p.id === propId);

if (!match) throw new Error(`Property "${propId}" not found in config`);

return [{ json: match }];

const prop = $('Find property').first().json;
const meta = $input.first().json;
return [{ json: { ...prop, lastModified: meta.lastModifiedDateTime } }];

const prop   = $('Merge metadata').first().json;
const sheets = $input.first().json.value || [];

// Match the licensee tab by PATTERN — names vary across locations
// ("BOT - NEW ACTIVE LICENSEE", "BOT - Active Licensee Lists", etc.)
const norm = s => String(s.name || '').trim().toUpperCase();
const target =
     sheets.find(s => norm(s).includes('LICENSEE'))
  || sheets.find(s => norm(s) === 'ALL UNITS')
  || sheets.find(s => norm(s).startsWith('BOT'))
  || sheets[0];

const targetSheet = target ? target.name : 'Sheet1';
return [{ json: { ...prop, sheetName: targetSheet, sheetEncoded: encodeURIComponent(targetSheet) } }];

const prop = $('Pick data sheet').first().json;
const rows = $input.first().json.values || [];
const now  = new Date().toISOString();

// Reads the "BOT - NEW ACTIVE LICENSEE" tab (Layout A). Columns:
// Unit # | Unit Type | Unit SF | Unit status | Company Name | Business Owner | Phone # | Email | Onsite POC | notes
// Accept standard codes (A01-A, B05, DOCK14, G0A, R101) AND bare 1-2 letter
// block codes (F, B, C, G) that were previously dropped for having no digit.
// Bounded to <=2 letters so section labels like WAREHOUSE SPACE never match.
const unitPattern = /^(?:[A-Z]{1,5}\d{1,4}(?:[A-Z]|-[A-Z0-9]{1,3})?|[A-Z]{1,2})$/i;

function normType(typeText, unitId) {
  const t = String(typeText || '').toUpperCase();
  if (/OFFICE/.test(t)) return 'OFFICE';
  if (/DOCK|DEDICAT|SHARED/.test(t)) return 'DOCK';
  if (/TRAILER|TRUCK|VEHICLE|PARK/.test(t)) return 'TRAILER';
  if (/WAREHOUSE|^WH$|^W$/.test(t)) return 'WH';
  const u = unitId.toUpperCase();
  if (u.startsWith('R')) return 'OFFICE';
  if (u.startsWith('DOCK') || u.startsWith('DD')) return 'DOCK';
  if (u.startsWith('P') || u.startsWith('Y')) return 'TRAILER';
  return 'WH';
}

const clean = v => { const s = String(v==null?'':v).trim(); return (s && !/^hold$/i.test(s)) ? s : null; };

const units = [];
let inTable = false;
for (const row of rows) {
  const cells = row.map(c => String(c===null||c===undefined?'':c).trim());
  const [c0,c1,c2,c3='',c4='',c5='',c6='',c7='',c8='',c9=''] = cells;
  if (c0==='Unit #' && c1==='Unit Type') { inTable = true; continue; }
  if (!inTable) continue;
  const unitId = c0.replace(/\s+/g,'').toUpperCase();
  if (!unitPattern.test(unitId)) continue;
  const sf = Number(String(c2).replace(/[^0-9]/g,''))||0;
  const type = normType(c1, unitId);
  const statusNorm = c3.toLowerCase();
  const isHold = /hold/.test(statusNorm) || /hold/.test(c4.toLowerCase());
  const available = statusNorm === 'vacant' || isHold;
  const tenant = (statusNorm==='occupied' && c4) ? c4 : null;
  units.push({
    unit:unitId, type, sf, status:c3, tenant,
    owner: clean(c5), phone: clean(c6), email: clean(c7), poc: clean(c8), notes: clean(c9),
    available, hold:isHold
  });
}

function summarise(type) {
  const g=units.filter(u=>u.type===type), a=g.filter(u=>u.available);
  const ts=g.reduce((s,u)=>s+u.sf,0), as=a.reduce((s,u)=>s+u.sf,0);
  return { total_units:g.length, avail_units:a.length, total_sf:ts, avail_sf:as, avail_pct:ts>0?Math.round(as/ts*1000)/10:0 };
}

const wh=summarise('WH'), off=summarise('OFFICE'), dock=summarise('DOCK'), trailer=summarise('TRAILER');

const toStr=v=>({stringValue:String(v)}), toInt=v=>({integerValue:String(Math.round(v))}),
      toDbl=v=>({doubleValue:v}), toBool=v=>({booleanValue:v}), toNull=()=>({nullValue:null});

const summFs=s=>({mapValue:{fields:{total_units:toInt(s.total_units),avail_units:toInt(s.avail_units),total_sf:toInt(s.total_sf),avail_sf:toInt(s.avail_sf),avail_pct:toDbl(s.avail_pct)}}});
const unitFs=u=>({mapValue:{fields:{
  unit:toStr(u.unit), type:toStr(u.type), sf:toInt(u.sf), status:toStr(u.status),
  tenant:u.tenant?toStr(u.tenant):toNull(),
  owner:u.owner?toStr(u.owner):toNull(),
  phone:u.phone?toStr(u.phone):toNull(),
  email:u.email?toStr(u.email):toNull(),
  poc:u.poc?toStr(u.poc):toNull(),
  notes:u.notes?toStr(u.notes):toNull(),
  available:toBool(u.available), hold:toBool(u.hold)
}}});

const patchBody = { fields: {
  property:            toStr(prop.property||prop.id),
  address:             toStr(prop.address||''),
  yardi_url:           toStr(prop.yardi_url||''),
  sharepoint_url:      toStr(prop.sharepoint_url||''),
  sheet_last_modified: toStr(prop.lastModified||''),
  synced_at:           toStr(now),
  wh:      summFs(wh),  office: summFs(off),
  dock:    summFs(dock), parking: summFs(trailer),
  units: { arrayValue: { values: units.map(unitFs) } }
}};

return [{ json: { propId: prop.id, patchBody } }];

const body = $input.first().json.body || $input.first().json;
const raw  = (body.sharepoint_url || '').trim();
if (!raw) throw new Error('sharepoint_url is required');
if (!body.property) throw new Error('property name is required');

const propId = body.property.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

// Detect sharing links (/:x:/s/, /:x:/r/ etc.)
const isSharingLink = /\/:[a-z]+:\/[sr]\//i.test(raw);

if (isSharingLink) {
  const b64      = Buffer.from(raw).toString('base64').replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_');
  const shareId  = 'u!' + b64;
  const resolveUrl = `https://graph.microsoft.com/v1.0/shares/${shareId}/driveItem`;
  return [{ json: { ...body, propId, resolveUrl } }];
}

// Direct file path URL
const originMatch = raw.match(/^(https?:\/\/[^\/]+)/);
if (!originMatch) throw new Error('Invalid SharePoint URL');
const origin   = originMatch[1];
const pathname = raw.slice(origin.length).split('?')[0];
const rawParts = pathname.split('/').filter(Boolean);
const parts    = rawParts.map(p => { try { return decodeURIComponent(p); } catch(e) { return p; } });
const sitesIdx = parts.indexOf('sites');
if (sitesIdx < 0) throw new Error('Could not find /sites/ in SharePoint URL');

const siteRelPath     = '/' + parts.slice(0, sitesIdx + 2).join('/');
const encodedFilePath = rawParts.slice(sitesIdx + 2).join('/');
const resolveUrl      = `https://graph.microsoft.com/v1.0/sites/${origin.replace('https://','')}}:${siteRelPath}:/drive/root:/${encodedFilePath}`;

return [{ json: { ...body, propId, resolveUrl } }];

const prev = $('Parse URL + generate ID').first().json;
const item = $input.first().json;
const driveId = item.parentReference?.driveId || '';
const itemId  = item.id || '';
if (!driveId || !itemId) throw new Error('Could not resolve driveId/itemId from SharePoint URL');
return [{ json: { ...prev, driveId, itemId } }];

const prop   = $('Extract file IDs').first().json;
const config = $input.first().json;

const toStr = v => ({ stringValue: String(v || '') });

const arr = config.fields?.properties?.arrayValue?.values || [];

// Prevent duplicate IDs
if (arr.some(it => it.mapValue?.fields?.id?.stringValue === prop.propId)) {
  throw new Error(`Location "${prop.propId}" already exists in config. Edit it in Firestore directly.`);
}

const newEntry = {
  mapValue: {
    fields: {
      id:             toStr(prop.propId),
      driveId:        toStr(prop.driveId),
      itemId:         toStr(prop.itemId),
      property:       toStr(prop.property),
      address:        toStr(prop.address),
      yardi_url:      toStr(prop.yardi_url),
      sharepoint_url: toStr(prop.sharepoint_url)
    }
  }
};

const updatedValues = [...arr, newEntry];
const patchBody = { fields: { properties: { arrayValue: { values: updatedValues } } } };

return [{ json: { propId: prop.propId, pa: prop.pa || null, patchBody } }];
